using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    [DataRow(10, 1, 5, 2, DisplayName = "10 items, page 1, size 5 => 2 pages")]
    [DataRow(10, 2, 5, 2, DisplayName = "10 items, page 2, size 5 => 2 pages")]
    [DataRow(11, 1, 5, 3, DisplayName = "11 items, page 1, size 5 => 3 pages (ceiling)")]
    [DataRow(1, 1, 5, 1, DisplayName = "1 item, page 1, size 5 => 1 page")]
    [DataRow(0, 1, 5, 0, DisplayName = "0 items, page 1, size 5 => 0 pages")]
    public void Constructor_SetsPageIndexAndTotalPages(int count, int pageIndex, int pageSize, int expectedTotalPages)
    {
        // Arrange
        var items = new List<int>();

        // Act
        var sut = new PaginatedList<int>(items, count, pageIndex, pageSize);

        // Assert
        Assert.AreEqual(pageIndex, sut.PageIndex);
        Assert.AreEqual(expectedTotalPages, sut.TotalPages);
    }

    [TestMethod]
    public void Constructor_AddsItemsToList()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var sut = new PaginatedList<string>(items, 10, 1, 5);

        // Assert
        Assert.AreEqual(3, sut.Count);
        Assert.AreEqual("a", sut[0]);
        Assert.AreEqual("b", sut[1]);
        Assert.AreEqual("c", sut[2]);
    }

    [TestMethod]
    [DataRow(1, false, DisplayName = "Page 1 has no previous page")]
    [DataRow(2, true, DisplayName = "Page 2 has previous page")]
    [DataRow(3, true, DisplayName = "Page 3 has previous page")]
    public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
    {
        // Arrange
        var sut = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);

        // Act & Assert
        Assert.AreEqual(expected, sut.HasPreviousPage);
    }

    [TestMethod]
    [DataRow(1, 3, true, DisplayName = "Page 1 of 3 has next page")]
    [DataRow(2, 3, true, DisplayName = "Page 2 of 3 has next page")]
    [DataRow(3, 3, false, DisplayName = "Page 3 of 3 has no next page")]
    [DataRow(1, 1, false, DisplayName = "Page 1 of 1 has no next page")]
    public void HasNextPage_ReturnsCorrectValue(int pageIndex, int totalPages, bool expected)
    {
        // Arrange - calculate count from totalPages and pageSize
        int pageSize = 10;
        int count = totalPages * pageSize;
        var sut = new PaginatedList<int>(new List<int>(), count, pageIndex, pageSize);

        // Act & Assert
        Assert.AreEqual(expected, sut.HasNextPage);
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsCorrectSlice()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(5, result[4]);
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
    }

    [TestMethod]
    public void Create_SecondPage_ReturnsCorrectSlice()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 5);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(6, result[0]);
        Assert.AreEqual(10, result[4]);
        Assert.AreEqual(2, result.PageIndex);
    }

    [TestMethod]
    public void Create_LastPartialPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 7).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 5);

        // Assert
        Assert.AreEqual(2, result.Count);
        Assert.AreEqual(6, result[0]);
        Assert.AreEqual(7, result[1]);
        Assert.AreEqual(2, result.TotalPages);
    }
}

