using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut;

    [TestInitialize]
    public void Setup()
    {
        _sut = new NotificationService();
        // Drain the static queue to ensure isolation
        while (_sut.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut?.Dispose();
    }

    [TestMethod]
    public void SendNotification_EnqueuesNotification_CanBeReceived()
    {
        // Act
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_MessageContainsDisplayName()
    {
        // Act
        _sut.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        StringAssert.Contains(notification.Message, "Chemistry");
        StringAssert.Contains(notification.Message, "created");
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_MessageContainsId()
    {
        // Act
        _sut.SendNotification("Course", "101", EntityOperation.UPDATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        StringAssert.Contains(notification.Message, "101");
        StringAssert.Contains(notification.Message, "updated");
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, "created", DisplayName = "CREATE operation")]
    [DataRow(EntityOperation.UPDATE, "updated", DisplayName = "UPDATE operation")]
    [DataRow(EntityOperation.DELETE, "deleted", DisplayName = "DELETE operation")]
    public void SendNotification_OperationType_MessageContainsCorrectVerb(EntityOperation operation, string expectedVerb)
    {
        // Act
        _sut.SendNotification("Entity", "1", "TestEntity", operation);

        // Assert
