using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.EntityFrameworkCore;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext CreateContext(string dbName = null)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName ?? Guid.NewGuid().ToString())
            .Options;
        return new SchoolContext(options);
    }

    private void SeedStudents(SchoolContext context)
    {
        context.Students.AddRange(
            new Student { FirstMidName = "Alice", LastName = "Anderson", EnrollmentDate = new DateTime(2020, 1, 15) },
            new Student { FirstMidName = "Bob", LastName = "Brown", EnrollmentDate = new DateTime(2019, 9, 1) },
            new Student { FirstMidName = "Carol", LastName = "Clark", EnrollmentDate = new DateTime(2021, 6, 1) }
        );
        context.SaveChanges();
    }

    // ===== INDEX TESTS =====

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithPaginatedStudents()
    {
        // Arrange
        using var context = CreateContext();
        SeedStudents(context);
        var controller = new StudentsController(context);

        // Act
        var result = controller.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count);
        // Default sort is by LastName ascending
        Assert.AreEqual("Anderson", model[0].LastName);
        Assert.AreEqual("Brown", model[1].LastName);
        Assert.AreEqual("Clark", model[2].LastName);
    }

    [TestMethod]
    public void Index_SortByNameDesc_OrdersDescending()
    {
        // Arrange
        using var context = CreateContext();
        SeedStudents(context);
        var controller = new StudentsController(context);

        // Act
        var result = controller.Index("name_desc", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Clark", model[0].LastName);
        Assert.AreEqual("Brown", model[1].LastName);
        Assert.AreEqual("Anderson", model[2].LastName);
    }

    [TestMethod]
    public void Index_SortByDate_OrdersByEnrollmentDateAscending()
    {
        // Arrange
        using var context = CreateContext();
        SeedStudents(context);
        var controller = new StudentsController(context);

        // Act
        var result = controller.Index("Date", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Brown", model[0].LastName); // 2019
        Assert.AreEqual("Anderson", model[1].LastName); // 2020
        Assert.AreEqual("Clark", model[2].LastName); // 2021
    }

    [TestMethod]
    public void Index_SortByDateDesc_OrdersByEnrollmentDateDescending()
    {
        // Arrange
        using var context = CreateContext();
        SeedStudents(context);
        var controller = new StudentsController(context);

        // Act
        var result = controller.Index("date_desc", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Clark", model[0].LastName); // 2021
        Assert.AreEqual("Anderson", model[1].LastName); // 2020
        Assert.AreEqual("Brown", model[2].LastName); // 2019
    }

    [TestMethod]
    public void Index_SearchByLastName_FiltersCorrectly()
    {
        // Arrange
        using var context = CreateContext();
        SeedStudents(context);
        var controller = new StudentsController(context);

        // Act
        var result = controller.Index(null, null, "Brown", null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Brown", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchByFirstName_FiltersCorrectly()
    {
        // Arrange
        using var context = CreateContext();
        SeedStudents(context);
        var controller = new StudentsController(context);

        // Act
        var result = controller.Index(null, null, "Alice", null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Anderson", model[0].LastName);
    }

    [TestMethod]
    public void Index_NewSearchString_ResetsToPage1()
    {
        // Arrange
        using var context = CreateContext();
        SeedStudents(context);
        var controller = new StudentsController(context);

        // Act - provide a searchString (new search), page should reset to 1
        var result = controller.Index(null, null, "Brown", 5) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.PageIndex);
    }

    [TestMethod]
    public void Index_NoSearchString_UsesCurrentFilter()
    {
        // Arrange
        using var context = CreateContext();
        SeedStudents(context);
        var controller = new StudentsController(context);

        // Act - no searchString but currentFilter is set
        var result = controller.Index(null, "Brown", null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Brown", model[0].LastName);
    }

    [TestMethod]
    public void Index_SetsViewBagSortParameters()
    {
        // Arrange
        using var context = CreateContext();
        SeedStudents(context);
        var controller = new StudentsController(context);

        // Act
        controller.Index(null, null, null, null);

        // Assert - when sortOrder is null/empty, NameSortParm should be "name_desc"
        Assert.AreEqual("name_desc", controller.ViewBag.NameSortParm);
        Assert.AreEqual("Date", controller.ViewBag.DateSortParm);
    }

    // ===== DETAILS TESTS =====

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Arrange
        using var context = CreateContext();
        var controller = new StudentsController(context);

        // Act
        var result = controller.Details(null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        using var context = CreateContext();
        var student = new Student { FirstMidName = "Alice", LastName = "Anderson", EnrollmentDate = DateTime.Today };
        context.Students.Add(student);
        context.SaveChanges();
        var controller = new StudentsController(context);

        // Act
        var result = controller.Details(student.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual("Alice", model.FirstMidName);
        Assert.AreEqual("Anderson", model.LastName);
    }

    // ===== CREATE TESTS =====

    [TestMethod]
    public void Create_Get_ReturnsViewWithStudentDefaultDate()
    {
        // Arrange
        using var context = CreateContext();
        var controller = new StudentsController(context);

        // Act
        var result = controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
    }

    [TestMethod]
    public void Create_Post_ValidModel_AddsStudentAndRedirectsToIndex()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        var controller = new StudentsController(context);
        var student = new Student
        {
            FirstMidName = "John",
            LastName = "Doe",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        // Act
        var result = controller.Create(student);

        // Assert
        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);

        // Verify student was saved
        using var verifyContext = CreateContext(dbName);
        Assert.AreEqual(1, verifyContext.Students.Count());
        var saved = verifyContext.Students.First();
        Assert.AreEqual("Doe", saved.LastName);
        Assert.AreEqual("John", saved.FirstMidName);
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsViewWithStudent()
    {
        // Arrange
        using var context = CreateContext();
        var controller = new StudentsController(context);
        controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student { FirstMidName = "John", LastName = "", EnrollmentDate = DateTime.Today };

        // Act
        var result = controller.Create(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual("John", model.FirstMidName);
    }

    [TestMethod]
    public void Create_Post_MinValueEnrollmentDate_AddsModelError()
    {
        // Arrange
        using var context = CreateContext();
        var controller = new StudentsController(context);
        var student = new Student
        {
            FirstMidName = "John",
            LastName = "Doe",
            EnrollmentDate = DateTime.MinValue
        };

        // Act
        var result = controller.Create(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsFalse(controller.ModelState.IsValid);
        Assert.IsTrue(controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    // ===== EDIT TESTS =====

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        // Arrange
        using var context = CreateContext();
        var controller = new StudentsController(context);

        // Act
        var result = controller.Edit((int?)null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        using var context = CreateContext();
        var student = new Student { FirstMidName = "Alice", LastName = "Anderson", EnrollmentDate = DateTime.Today };
        context.Students.Add(student);
        context.SaveChanges();
        var controller = new StudentsController(context);

        // Act
        var result = controller.Edit((int?)student.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual("Alice", model.FirstMidName);
    }

    [TestMethod]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        // Arrange
        using var context = CreateContext();
        var controller = new StudentsController(context);

        // Act
        var result = controller.Edit((int?)999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Edit_Post_ValidModel_UpdatesAndRedirects()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using (var seedContext = CreateContext(dbName))
        {
            seedContext.Students.Add(new Student
            {
                ID = 1,
                FirstMidName = "Alice",
                LastName = "Anderson",
                EnrollmentDate = new DateTime(2020, 1, 1)
            });
            seedContext.SaveChanges();
        }

        using var testContext = CreateContext(dbName);
        var controller = new StudentsController(testContext);
        var updatedStudent = new Student
        {
            ID = 1,
            FirstMidName = "Alice",
            LastName = "Smith",
            EnrollmentDate = new DateTime(2020, 1, 1)
        };

        // Act
        var result = controller.Edit(updatedStudent);

        // Assert
        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
    }

    [TestMethod]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        // Arrange
        using var context = CreateContext();
        var controller = new StudentsController(context);
        controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student { FirstMidName = "Alice", LastName = "", EnrollmentDate = DateTime.Today };

        // Act
        var result = controller.Edit(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Edit_Post_MinValueEnrollmentDate_AddsModelError()
    {
        // Arrange
        using var context = CreateContext();
        var controller = new StudentsController(context);
        var student = new Student
        {
            FirstMidName = "John",
            LastName = "Doe",
            EnrollmentDate = DateTime.MinValue
        };

        // Act
        var result = controller.Edit(student) as ViewResult;

        // Assert
