    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesStudentAndRedirects()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        int studentId;
        using (var seedContext = CreateContext(dbName))
        {
            var student = new Student { FirstMidName = "Alice", LastName = "Anderson", EnrollmentDate = DateTime.Today };
            seedContext.Students.Add(student);
            seedContext.SaveChanges();
            studentId = student.ID;
        }

        using var testContext = CreateContext(dbName);
        var controller = new StudentsController(testContext);

        // Act
