{
    private Mock<IWebHostEnvironment> _envMock;
    private Mock<ILogger<CoursesController>> _loggerMock;

    [TestInitialize]
    public void Setup()
    {
        _envMock = new Mock<IWebHostEnvironment>();
        _envMock.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
        _envMock.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
        _loggerMock = new Mock<ILogger<CoursesController>>();
    }

    private SchoolContext CreateContext(string dbName = null)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName ?? Guid.NewGuid().ToString())
            .Options;
        return new SchoolContext(options);
    }

    private (Department dept, Course course) SeedCourseWithDepartment(SchoolContext context)
    {
        var dept = new Department
        {
            Name = "Engineering",
            Budget = 100000m,
            StartDate = new DateTime(2020, 1, 1)
        };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };
        context.Courses.Add(course);
        context.SaveChanges();

        return (dept, course);
    }

    // ===== INDEX TESTS =====

    [TestMethod]
    public void Index_ReturnsViewWithCourses()
    {
        // Arrange
        using var context = CreateContext();
        SeedCourseWithDepartment(context);
        var controller = new CoursesController(context, _envMock.Object, _loggerMock.Object);

        // Act
        var result = controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as System.Collections.Generic.List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Chemistry", model[0].Title);
    }

    // ===== DETAILS TESTS =====

