        var controller = new CoursesController(context, _envMock.Object, _loggerMock.Object);

        // Act
        var result = controller.Details(null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithCourse()
    {
        // Arrange
        using var context = CreateContext();
        var (_, course) = SeedCourseWithDepartment(context);
        var controller = new CoursesController(context, _envMock.Object, _loggerMock.Object);

        // Act
        var result = controller.Details(course.CourseID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Course;
        Assert.IsNotNull(model);
        Assert.AreEqual("Chemistry", model.Title);
        Assert.AreEqual(3, model.Credits);
    }

