namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class InstructorsControllerTests
{
    private SchoolContext CreateContext(string dbName = null)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName ?? Guid.NewGuid().ToString())
            .Options;
        return new SchoolContext(options);
    }

    private Instructor SeedInstructorWithCourse(SchoolContext context)
    {
        var dept = new Department { Name = "Math", Budget = 50000m, StartDate = DateTime.Today };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course = new Course { CourseID = 1050, Title = "Calculus", Credits = 4, DepartmentID = dept.DepartmentID };
        context.Courses.Add(course);
        context.SaveChanges();

        var instructor = new Instructor
        {
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = new DateTime(2000, 1, 1),
            CourseAssignments = new List<CourseAssignment>(),
            OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
        };
        context.Instructors.Add(instructor);
        context.SaveChanges();

        var assignment = new CourseAssignment { InstructorID = instructor.ID, CourseID = course.CourseID };
        context.CourseAssignments.Add(assignment);
        context.SaveChanges();

        // Reload to ensure navigation properties are populated
        context.Entry(instructor).Collection(i => i.CourseAssignments).Load();

        return instructor;
    }

    // ===== INDEX TESTS =====

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithInstructors()
    {
        // Arrange
        using var context = CreateContext();
        context.Instructors.Add(new Instructor
        {
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = new DateTime(2000, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        });
        context.Instructors.Add(new Instructor
        {
            FirstMidName = "Fadi",
            LastName = "Fakhouri",
            HireDate = new DateTime(2002, 7, 6),
            CourseAssignments = new List<CourseAssignment>()
        });
        context.SaveChanges();
        var controller = new InstructorsController(context);

        // Act
        var result = controller.Index(null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Instructors.Count());
    }

    [TestMethod]
    public void Index_WithInstructorId_PopulatesCourses()
    {
        // Arrange
        using var context = CreateContext();
        var instructor = SeedInstructorWithCourse(context);
        var controller = new InstructorsController(context);

        // Act
        var result = controller.Index(instructor.ID, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Courses);
        Assert.AreEqual(1, model.Courses.Count());
        Assert.AreEqual("Calculus", model.Courses.First().Title);
    }

    // ===== DETAILS TESTS =====

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Arrange
        using var context = CreateContext();
        var controller = new InstructorsController(context);

        // Act
        var result = controller.Details(null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, ((StatusCodeResult)result).StatusCode);
