using System;

namespace ContosoUniversity.Tests.Controllers;

/// <summary>
/// Tests for BaseController functionality via a concrete test subclass.
/// BaseController is abstract, so we create a minimal concrete subclass for testing.
/// </summary>
[TestClass]
public sealed class BaseControllerTests
{
    /// <summary>
    /// Minimal concrete implementation of BaseController for testing.
    /// </summary>
    private sealed class TestableBaseController : BaseController
    {
        public TestableBaseController(SchoolContext context) : base(context) { }

        public void TestSendEntityNotification(string entityType, string entityId, EntityOperation operation)
        {
            SendEntityNotification(entityType, entityId, operation);
        }

        public void TestSendEntityNotification(string entityType, string entityId, string entityDisplayName, EntityOperation operation)
        {
            SendEntityNotification(entityType, entityId, entityDisplayName, operation);
        }

        public SchoolContext GetDbContext() => db;
    }

    private SchoolContext CreateContext(string dbName = null)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName ?? Guid.NewGuid().ToString())
