using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using System;
using System.ComponentModel.DataAnnotations;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Models;

/// <summary>
/// Tests for domain model properties, computed values, and validation attributes.
/// </summary>
[TestClass]
public sealed class DomainModelTests
{
    private static IList<ValidationResult> ValidateModel(object model)
    {
        var results = new List<ValidationResult>();
        var ctx = new ValidationContext(model);
        Validator.TryValidateObject(model, ctx, results, validateAllProperties: true);
        return results;
    }

    // ===== COURSE TESTS =====

    [TestMethod]
    public void Course_Properties_CanBeSetAndRetrieved()
    {
        // Arrange & Act
        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 1,
            TeachingMaterialImagePath = "/uploads/img.png"
        };

        // Assert
        Assert.AreEqual(1050, course.CourseID);
        Assert.AreEqual("Chemistry", course.Title);
        Assert.AreEqual(3, course.Credits);
        Assert.AreEqual(1, course.DepartmentID);
        Assert.AreEqual("/uploads/img.png", course.TeachingMaterialImagePath);
    }

    [TestMethod]
    [DataRow(0, true, DisplayName = "Credits 0 is valid")]
    [DataRow(3, true, DisplayName = "Credits 3 is valid")]
    [DataRow(5, true, DisplayName = "Credits 5 is valid")]
    [DataRow(-1, false, DisplayName = "Credits -1 is invalid")]
    [DataRow(6, false, DisplayName = "Credits 6 is invalid")]
    public void Course_Credits_RangeValidation(int credits, bool shouldBeValid)
    {
        // Arrange
        var course = new Course { CourseID = 1, Title = "Test", Credits = credits, DepartmentID = 1 };

        // Act
        var results = ValidateModel(course);

        // Assert
        var hasCreditsError = results.Any(r => r.MemberNames.Contains("Credits"));
        Assert.AreEqual(shouldBeValid, !hasCreditsError,
            $"Credits={credits}: expected valid={shouldBeValid}, but got error={hasCreditsError}");
    }

    [TestMethod]
    public void Course_Title_MaxLength50_ValidationFails()
    {
        // Arrange
        var course = new Course
        {
            CourseID = 1,
            Title = new string('A', 51), // exceeds 50 char limit
            Credits = 3,
            DepartmentID = 1
        };

        // Act
        var results = ValidateModel(course);

        // Assert
        Assert.IsTrue(results.Any(r => r.MemberNames.Contains("Title")));
    }

    [TestMethod]
    public void Course_Title_MinLength3_ValidationFails()
    {
        // Arrange
        var course = new Course
        {
            CourseID = 1,
            Title = "AB", // less than 3 chars
            Credits = 3,
            DepartmentID = 1
        };

        // Act
        var results = ValidateModel(course);

        // Assert
        Assert.IsTrue(results.Any(r => r.MemberNames.Contains("Title")));
    }

    // ===== ENROLLMENT TESTS =====

    [TestMethod]
    public void Enrollment_Grade_CanBeNull()
    {
        // Arrange
        var enrollment = new Enrollment
        {
            EnrollmentID = 1,
            CourseID = 1,
            StudentID = 1,
            Grade = null
        };

        // Assert
        Assert.IsNull(enrollment.Grade);
    }

    [TestMethod]
    [DataRow(Grade.A, DisplayName = "Grade A")]
    [DataRow(Grade.B, DisplayName = "Grade B")]
    [DataRow(Grade.C, DisplayName = "Grade C")]
    [DataRow(Grade.D, DisplayName = "Grade D")]
    [DataRow(Grade.F, DisplayName = "Grade F")]
    public void Enrollment_Grade_AllValidGrades(Grade grade)
    {
        // Arrange
        var enrollment = new Enrollment { EnrollmentID = 1, CourseID = 1, StudentID = 1, Grade = grade };

        // Assert
        Assert.AreEqual(grade, enrollment.Grade);
    }

    // ===== DEPARTMENT TESTS =====

    [TestMethod]
    public void Department_Properties_CanBeSetAndRetrieved()
    {
        // Arrange & Act
        var startDate = new DateTime(2020, 9, 1);
        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 350000m,
            StartDate = startDate,
            InstructorID = 5
        };

        // Assert
        Assert.AreEqual(1, dept.DepartmentID);
        Assert.AreEqual("Engineering", dept.Name);
        Assert.AreEqual(350000m, dept.Budget);
        Assert.AreEqual(startDate, dept.StartDate);
        Assert.AreEqual(5, dept.InstructorID);
    }

    [TestMethod]
    public void Department_InstructorID_CanBeNull()
    {
        // Arrange
        var dept = new Department
        {
            Name = "No Admin",
            Budget = 100000m,
            StartDate = DateTime.Today,
            InstructorID = null
        };

        // Assert
        Assert.IsNull(dept.InstructorID);
    }

    [TestMethod]
    public void Department_Name_MaxLength50_ValidationFails()
    {
        // Arrange
        var dept = new Department
        {
            Name = new string('A', 51),
            Budget = 100000m,
            StartDate = DateTime.Today
        };

        // Act
        var results = ValidateModel(dept);

        // Assert
        Assert.IsTrue(results.Any(r => r.MemberNames.Contains("Name")));
    }

    // ===== NOTIFICATION TESTS =====

    [TestMethod]
    public void Notification_Properties_CanBeSetAndRetrieved()
    {
        // Arrange & Act
        var now = DateTime.Now;
        var notification = new Notification
        {
            Id = 1,
            EntityType = "Student",
            EntityId = "42",
            Operation = "CREATE",
            Message = "New student created",
            CreatedAt = now,
            CreatedBy = "admin",
            IsRead = false,
            ReadAt = null
        };

        // Assert
        Assert.AreEqual(1, notification.Id);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("New student created", notification.Message);
        Assert.AreEqual(now, notification.CreatedAt);
        Assert.AreEqual("admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
        Assert.IsNull(notification.ReadAt);
    }

    [TestMethod]
    public void Notification_IsRead_CanBeToggled()
    {
        // Arrange
        var notification = new Notification { EntityType = "T", EntityId = "1", Operation = "C", Message = "M", CreatedAt = DateTime.Now };

        // Act
        notification.IsRead = true;
        notification.ReadAt = DateTime.Now;

        // Assert
        Assert.IsTrue(notification.IsRead);
        Assert.IsNotNull(notification.ReadAt);
    }

    // ===== STUDENT TESTS =====

    [TestMethod]
    public void Student_InheritsFromPerson()
    {
        // Arrange & Act
        var student = new Student
        {
            ID = 1,
            FirstMidName = "Alice",
            LastName = "Johnson",
            EnrollmentDate = DateTime.Today
        };

        // Assert
        Assert.IsInstanceOfType<Person>(student);
        Assert.AreEqual("Johnson, Alice", student.FullName);
    }

    // ===== INSTRUCTOR TESTS =====

    [TestMethod]
    public void Instructor_InheritsFromPerson()
    {
        // Arrange & Act
        var instructor = new Instructor
        {
            ID = 1,
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = new DateTime(2000, 1, 1)
        };

        // Assert
        Assert.IsInstanceOfType<Person>(instructor);
        Assert.AreEqual("Abercrombie, Kim", instructor.FullName);
    }

    // ===== OFFICE ASSIGNMENT TESTS =====

    [TestMethod]
    public void OfficeAssignment_Properties_CanBeSetAndRetrieved()
    {
        // Arrange & Act
        var office = new OfficeAssignment
        {
            InstructorID = 5,
            Location = "Room 301"
        };

        // Assert
        Assert.AreEqual(5, office.InstructorID);
        Assert.AreEqual("Room 301", office.Location);
    }

    [TestMethod]
    public void OfficeAssignment_Location_MaxLength50_ValidationFails()
    {
        // Arrange
        var office = new OfficeAssignment
        {
            InstructorID = 1,
            Location = new string('A', 51)
        };

        // Act
        var results = ValidateModel(office);

        // Assert
        Assert.IsTrue(results.Any(r => r.MemberNames.Contains("Location")));
    }

    // ===== COURSE ASSIGNMENT TESTS =====

    [TestMethod]
    public void CourseAssignment_Properties_CanBeSetAndRetrieved()
    {
        // Arrange & Act
        var assignment = new CourseAssignment
        {
            InstructorID = 3,
            CourseID = 1050
        };

        // Assert
        Assert.AreEqual(3, assignment.InstructorID);
        Assert.AreEqual(1050, assignment.CourseID);
    }
}

